const d = $json;
const esc = s => String(s).replace(/[&<>]/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;' }[c]));
const upcoming = (d.dueThisWeek || []).map(t => `<li style="margin:6px 0">${esc(t.title)}${t.due_at ? ` — <b>${new Date(t.due_at).toLocaleDateString(undefined,{weekday:'short',month:'short',day:'numeric'})}</b>` : ''}</li>`).join('') || '<li style="color:#64748b">Nothing due this week — enjoy it! 🎉</li>';
const card = (label, val, color) => `<td align="center" style="padding:14px 8px"><div style="font-size:28px;font-weight:800;color:${color}">${val}</div><div style="font-size:12px;color:#64748b;text-transform:uppercase;letter-spacing:.5px">${label}</div></td>`;
const html = `<div style="font-family:-apple-system,Segoe UI,Roboto,sans-serif;max-width:560px;margin:0 auto;background:#fff">
  <div style="background:#6366f1;padding:24px;border-radius:14px 14px 0 0"><div style="color:#c7d2fe;font-size:12px;font-weight:700;letter-spacing:1px">TASKFLOW</div><div style="color:#fff;font-size:22px;font-weight:800">Your week at a glance</div></div>
  <div style="border:1px solid #e6e8ec;border-top:none;border-radius:0 0 14px 14px;padding:8px 20px 24px">
    <table width="100%" style="border-collapse:collapse;margin:8px 0 4px"><tr>${card('Completed', d.completedThisWeek, '#10b981')}${card('Pending', d.pending, '#6366f1')}${card('Overdue', d.overdue, '#ef4444')}</tr></table>
    <p style="color:#334155;font-size:14px;margin:16px 0 6px"><b>Due this week</b></p>
    <ul style="padding-left:18px;color:#334155;font-size:14px;margin:0">${upcoming}</ul>
    <p style="color:#94a3b8;font-size:12px;margin-top:20px">Open tasks by priority — 🔴 ${d.byPriority.high} high · 🟡 ${d.byPriority.medium} medium · 🟢 ${d.byPriority.low} low. You created ${d.createdThisWeek} new task(s) this week.</p>
  </div>
</div>`;
return { json: { html, subject: `TaskFlow weekly digest — ${d.pending} open, ${d.overdue} overdue` } };
